(()=>{'use strict';
const app=document.getElementById('app'),SB='https://saodmeoilixfdqentofp.supabase.co',B='doit-files',STORE='perf-soft-v2';
const C={sales:'ยอดขาย',giv:'ยอด GIV',moq:'MOQ',dc1:'DC1 / CD1',dc2:'DC2 / CD2',dc3:'DC3 / CD3',cd13:'CD1+CD3',bills:'บิลซื้อ',gps:'GPS',dgp:'Golden Point'},OVER=['sales','giv','moq','dc1','dc2','dc3','cd13','bills','dgp'];
let data=null,state=st(),renderSeq=0;
const K=()=>Object.keys(C),N=x=>Number.isFinite(+x)?+x:0,M=x=>N(x).toLocaleString('th-TH',{maximumFractionDigits:0}),P=x=>N(x).toLocaleString('th-TH',{maximumFractionDigits:1,minimumFractionDigits:1})+'%',E=x=>String(x??'').replaceAll('&','&amp;').replaceAll('<','&lt;').replaceAll('>','&gt;').replaceAll(String.fromCharCode(34),'&quot;');
function st(){const q=new URLSearchParams(location.search),lv=q.get('level')||'',md=q.get('mode')||({compare:'compare','compare-detail':'compare',ads:'ads',ps:'ps',person:'person',ms:'ms',ds:'ds'}[lv]||'ds');return{mode:md,cat:q.get('cat')||'',ads:q.get('ads')||'',ps:q.get('ps')||'',cmp:q.get('cmp')||'prev'}}
function go(s,push=true){state={mode:s.mode||state.mode||'ds',cat:s.cat??'',ads:s.ads??'',ps:s.ps??'',cmp:s.cmp??state.cmp??'prev'};if(push){const q=new URLSearchParams();q.set('mode',state.mode);if(state.cat)q.set('cat',state.cat);if(state.ads)q.set('ads',state.ads);if(state.ps)q.set('ps',state.ps);if(state.mode==='compare'&&state.cmp&&state.cmp!=='prev')q.set('cmp',state.cmp);history.pushState(state,'',location.pathname+'?'+q.toString())}render();requestAnimationFrame(()=>scrollTo({top:0,behavior:'smooth'}))}
window.onpopstate=()=>{state=st();render()};document.addEventListener('click',e=>{const b=e.target.closest('[data-mode]');if(!b)return;e.preventDefault();go({mode:b.dataset.mode,cat:b.dataset.cat||'',ads:b.dataset.ads||'',ps:b.dataset.ps||'',cmp:b.dataset.cmp||state.cmp||'prev'})});
function btn(t,s,cls='chip'){const on=state.mode===s.mode&&(s.cat===undefined||state.cat===s.cat)&&(s.ads===undefined||state.ads===s.ads)&&(s.cmp===undefined||state.cmp===s.cmp);return`<button class='${cls}${on?' on':''}' data-mode='${E(s.mode)}' data-cat='${E(s.cat||'')}' data-ads='${E(s.ads||'')}' data-ps='${E(s.ps||'')}' data-cmp='${E(s.cmp||'')}'>${E(t)}</button>`}
function nav(){return`<div class='nav'>${btn('DS',{mode:'ds'})}${btn('ADS',{mode:'ads'})}${btn('เทียบย้อนหลัง',{mode:'compare'})}${btn('MS แยก',{mode:'ms'})}</div>`}
async function jf(p,ms=8000){const ac=new AbortController(),t=setTimeout(()=>ac.abort(),ms);try{let r=await fetch(SB+'/storage/v1/object/public/'+B+'/'+p,{cache:'no-store',signal:ac.signal});if(!r.ok)r=await fetch(SB+'/storage/v1/object/'+B+'/'+p,{cache:'no-store',signal:ac.signal});const txt=await r.text();if(!r.ok)throw Error(r.status+' '+txt);return JSON.parse(txt)}finally{clearTimeout(t)}}
function dl(){return N(data?.meta?.daysLeft)||Math.max(N(data?.meta?.totalWorkdays)-N(data?.meta?.workdayNo),0)}function pc(v){const d=N(v?.daysLeft)||dl(),r=Math.max(N(v?.remaining)||(N(v?.target)-N(v?.actual)),0),p=N(v?.perDay)||(d>0?r/d:r);return{d,r,p}}function pct(v){const x=pc(v);return'เหลือ '+M(x.r)+' / วันละ '+M(x.p)}function oldLabel(p){return p?.reportKey||(p?.period&&p?.workdayNo?String(p.period)+'-WD'+String(p.workdayNo).padStart(2,'0'):'ก่อนหน้า')}
function meter(v){return`<div class='meter'><div class='fill' style='width:${Math.max(0,Math.min(140,N(v)))}%'></div></div>`}
function kpis(r){const s=r?.sales||{},x=pc(s);return`<div class='kpis'><div class='kpi'><span>Target</span><b>${M(s.target)}</b><small>ยอดขาย</small></div><div class='kpi'><span>Actual</span><b>${M(s.actual)}</b><small>ยอดขาย</small></div><div class='kpi'><span>เหลือเป้า</span><b>${M(x.r)}</b><small>ยอดขาย</small></div><div class='kpi'><span>ต้องทำ/วัน</span><b>${M(x.p)}</b><small>เหลือ ${M(x.d)} วัน</small></div><div class='kpi'><span>Index</span><b>${P(s.index)}</b><small>ตามชีท</small></div><div class='kpi'><span>GIV</span><b>${M(r?.giv?.actual)}</b><small>${pct(r?.giv)}</small></div><div class='kpi'><span>บิล</span><b>${M(r?.bills?.actual)}</b><small>${pct(r?.bills)}</small></div><div class='kpi'><span>DGP</span><b>${M(r?.dgp?.actual)}</b><small>${pct(r?.dgp)}</small></div></div>`}
function hero(t,sub,r){return`<section class='panel fade'><div class='title'>${E(t)}</div><div class='muted'>${E(sub)}</div>${kpis(r||{})}</section>`}
function statusPanel(){const m=data?.meta||{},same=m.sameDayRevisions||m.sameDayRevisionCount||N(m.revision);return`<section class='panel fade'><h3>Data Status</h3><div class='muted'>reportDate คือวันรายงานจริง · uploadedAt เป็นเวลาอัปโหลด · sameDayRevisions ใช้แยก revision วันเดียวกันไม่ให้เทียบเป็นเมื่อวาน</div><div class='statusgrid'><div class='card'><b>${E(m.reportDate||m.reportKey||'-')}</b><span>Report Date / Key</span></div><div class='card'><b>${E(m.uploadedAt||m.generatedAt||'-')}</b><span>Uploaded / Generated</span></div><div class='card'><b>${M(same)}</b><span>sameDayRevisions / revision</span></div></div></section>`}
function sum(rows,code){const r={code,name:code};K().forEach(k=>{let t=0,a=0,ix=0,c=0;(rows||[]).forEach(x=>{t+=N(x[k]?.target);a+=N(x[k]?.actual);ix+=N(x[k]?.index);c++});r[k]={target:t,actual:a,index:t?a/t*100:(c?ix/c:0)}});return r}
function row(r,i,k,s){const v=r[k]||{};return`<button class='row' data-mode='${E(s.mode)}' data-cat='${E(s.cat||'')}' data-ads='${E(s.ads||'')}' data-ps='${E(s.ps||'')}'><div class='no'>${i+1}</div><div class='rowMain'><div class='rowHead'><b>${E(r.ps||r.ads||r.code)} · ${E(r.name||'')}</b></div><span class='rowSub'>Target ${M(v.target)} / Actual ${M(v.actual)} / ${pct(v)}</span>${meter(v.index)}</div><div class='right'>${P(v.index)}</div></button>`}
function rank(rows,k,next){return`<div class='rank'>${(rows||[]).map((r,i)=>row(r,i,k,next==='ads'?{mode:'ps',ads:r.code||r.ads}:next==='ps'?{mode:'person',ads:r.ads,ps:r.ps}:{mode:'ds'})).join('')}</div>`}
function cats(rows,title,next){return`<section class='panel'><h3>${E(title)}</h3><div class='catgrid'>${K().map(k=>{const rr=[...(rows||[])].sort((a,b)=>N(b[k]?.index)-N(a[k]?.index)).slice(0,5);return`<div class='panel'><h3>${E(C[k])}</h3>${rank(rr,k,next)}</div>`}).join('')}</div></section>`}
function trendPanel(){return`<section class='panel'><h3>Month Trend Dashboard</h3><div class='muted'>ดูแนวโน้มจากไฟล์ history-index เมื่อเข้าเมนูเทียบย้อนหลัง ระบบจะกัน sameDayRevisions ไม่ให้เอา revision วันเดียวกันมาเป็นวันก่อนหน้า</div><span class='badge'>Smart Compare วันต่อวัน</span><span class='badge'>sameDayRevisions safe</span><span class='badge'>reportDate-aware</span></section>`}
function screenDs(){const m=data.meta||{};return nav()+statusPanel()+hero('DS ภาพรวม','ไฟล์ '+(m.reportKey||'')+' · WD '+(m.workdayNo||'-')+'/'+(m.totalWorkdays||'-'),data.ds)+`<section class='panel'><div class='grid'>${btn('ดู ADS ทั้ง 4',{mode:'ads'},'chip')}${btn('Smart Compare วันต่อวัน',{mode:'compare'},'chip')}</div></section>`+cats(data.ads,'ADS Board','ads')+cats(data.ps,'Top PS / ต้องเร่งก่อน','ps')+trendPanel()}
function adsOverallRank(){const rows=[...(data.ads||[])].map(r=>{const used=OVER.filter(k=>N(r[k]?.index)>0),score=used.length?used.reduce((s,k)=>s+N(r[k]?.index),0)/used.length:0;return{r,score,count:used.length}}).sort((a,b)=>b.score-a.score);return`<div class='rank'>${rows.map((x,i)=>`<button class='row' data-mode='ps' data-ads='${E(x.r.ads||x.r.code)}'><div class='no'>${i+1}</div><div class='rowMain'><div class='rowHead'><b>${E(x.r.ads||x.r.code)} · ${E(x.r.name||x.r.code||'')}</b></div><span class='rowSub'>เฉลี่ยทุกเป้า ${P(x.score)} / ${x.count} เป้า / ยอดขาย ${P(x.r.sales?.index)} / DGP ${P(x.r.dgp?.index)}</span>${meter(x.score)}</div><div class='right'>${P(x.score)}</div></button>`).join('')}</div>`}
function screenAds(){return nav()+hero('ADS ทั้ง 4','จัดตาม Seller Report',sum(data.ps,'ADS'))+`<section class='panel'><h3>ADS Rank</h3>${adsOverallRank()}</section>`+cats(data.ads,'จัดอันดับ ADS','ads')}
function screenPs(){const rows=(data.ps||[]).filter(x=>x.ads===(state.ads||'AYAADS01'));return nav()+hero((state.ads||'AYAADS01')+' · PS','ข้อมูลเฉพาะ ADS นี้',sum(rows,state.ads||'AYAADS01'))+`<section class='panel'><h3>PS Rank</h3>${rank(rows.sort((a,b)=>N(b.sales?.index)-N(a.sales?.index)),'sales','ps')}</section>`+cats(rows,'Seller Report Detail','ps')}
function screenPerson(){const p=(data.ps||[]).find(x=>x.ps===state.ps)||(data.ps||[])[0];return nav()+hero((p?.ps||'-')+' · '+(p?.name||''),'รายละเอียดตามชีท',p)+`<section class='panel'><h3>Raw tab</h3><div class='grid'>${K().map(k=>`<div class='card'><b>${E(C[k])}</b><span>Target ${M(p?.[k]?.target)} / Actual ${M(p?.[k]?.actual)}<br>${pct(p?.[k])}</span>${meter(p?.[k]?.index)}<small>${P(p?.[k]?.index)}</small></div>`).join('')}</div></section>`}
function avgMetric(list,k){let t=0,a=0,ix=0,c=0;list.forEach(r=>{const m=r?.[k]||{};t+=N(m.target);a+=N(m.actual);ix+=N(m.index);c++});return{target:c?t/c:0,actual:c?a/c:0,index:c?ix/c:0}}function avgOne(list,base){const r={...(base||{})};K().forEach(k=>r[k]=avgMetric(list,k));return r}function avgSet(packs,set,key){const first=packs[0]?.[set]||[],out=[];first.forEach(b=>{const id=b[key]||b.code,rows=packs.map(p=>(p?.[set]||[]).find(x=>(x[key]||x.code)===id)).filter(Boolean);if(rows.length)out.push(avgOne(rows,b))});return out}function avgPack(packs){return{meta:{reportKey:'AVG3'},ds:avgOne(packs.map(x=>x.ds).filter(Boolean),packs[0]?.ds||{}),ads:avgSet(packs,'ads','ads'),ps:avgSet(packs,'ps','ps')}}
function latestHist(rows,cur){const map=new Map();rows.forEach(x=>{const key=x.reportDate||x.reportKey||x.path;if(!key)return;if(x.path===cur.comparePath||x.path===cur.dataPath||x.reportKey===cur.reportKey)return;if(x.reportDate&&cur.reportDate&&x.reportDate===cur.reportDate)return;if(!map.has(key))map.set(key,x)});return[...map.values()]}
async function oldPack(kind='prev'){kind=kind||'prev';const key='perf-old-v2-'+kind+'-'+(data?.meta?.reportKey||'');try{const c=sessionStorage.getItem(key);if(c)return JSON.parse(c)}catch{}const hist=await jf('performance/history-index.json',8000),cur=data.meta||{};let older=latestHist(Array.isArray(hist)?hist.filter(x=>x&&x.path):[],cur);if(cur.reportDate)older=older.filter(x=>!x.reportDate||String(x.reportDate)<String(cur.reportDate));let pack;if(kind==='same'){const target=N(cur.workdayNo)-12,pick=older.find(x=>N(x.workdayNo)===target&&(!cur.period||!x.period||String(x.period)===String(cur.period)));if(!pick)throw Error('ยังไม่มีข้อมูลตลาดเดิมรอบก่อนในเดือนนี้');pack={pick:{...pick,reportKey:'ตลาดเดิม '+oldLabel(pick)},old:await jf(pick.path,12000)}}else if(kind==='avg3'){const picks=older.slice(0,3);if(!picks.length)throw Error('ยังไม่มีข้อมูลย้อนหลังสำหรับค่าเฉลี่ย');pack={pick:{reportKey:'เฉลี่ย '+picks.length+' วันล่าสุด'},old:avgPack(await Promise.all(picks.map(x=>jf(x.path,12000))))}}else{const pick=older[0];if(!pick)throw Error('ยังไม่มีไฟล์วันทำงานก่อนหน้าให้เทียบ');pack={pick:{...pick,reportKey:kind==='pace'?'Pace เป้า':oldLabel(pick)},old:await jf(pick.path,12000)}}try{sessionStorage.setItem(key,JSON.stringify(pack))}catch{}return pack}
function cmpSlider(){const m=data?.meta||{},wd=N(m.workdayNo),market=wd?((wd-1)%12)+1:'-',round=wd?Math.floor((wd-1)/12)+1:'-',items=[['prev','เทียบวันก่อน','ใช้ reportDate ก่อนหน้า ไม่ใช้ revision วันเดียวกัน'],['same','เทียบตลาดเดิม','ตลาด '+market+' รอบ '+round+' เทียบรอบก่อน'],['avg3','เฉลี่ย 3 วัน','เทียบกับค่าเฉลี่ยย้อนหลัง'],['pace','Pace เป้า','เพิ่มล่าสุดเทียบต้องทำต่อวัน']];return`<div class='muted'>เลือกรูปแบบการเทียบ</div><div class='cmpSlider'>${items.map(([k,t,d])=>`<button class='cmpCard ${state.cmp===k?'on':''}' data-mode='compare' data-cmp='${k}' data-cat='${E(state.cat||'')}' data-ads='${E(state.ads||'')}'><b>${E(t)}</b><span>${E(d)}</span></button>`).join('')}</div>`}
function cmpPair(c,o){if((state.cmp||'prev')==='pace'){const inc=Math.max(N(c?.actual)-N(o?.actual),0),pace=pc(c).p;return{a:inc,b:pace,d:inc-pace,ix:pace?inc/pace*100:0,oi:100}}const a=N(c?.actual),b=N(o?.actual);return{a,b,d:a-b,ix:N(c?.index),oi:N(o?.index)}}function diffBtn(cur,old,k,i){const r=cmpPair(cur[k]||{},old?.[k]||{}),cls=r.d>=0?'up':'dn',left=state.cmp==='pace'?`เพิ่ม ${M(r.a)} / Pace ${M(r.b)}`:`ล่าสุด ${M(r.a)} / ก่อนหน้า ${M(r.b)}`;return`<button class='card cmpCatCard' data-mode='compare' data-cat='${E(k)}' data-cmp='${E(state.cmp||'prev')}'><small>#${i+1}</small><b>${E(C[k])}</b><span>${left}<br>${pct(cur[k])}</span><strong class='diff ${cls}'>${r.d>=0?'+':''}${M(r.d)}</strong></button>`}
function by(a,k){const m=new Map();(a||[]).forEach(x=>m.set(x[k]||x.code,x));return m}function deltas(cur,old,k,id){const om=by(old,id);return(cur||[]).map(x=>{const o=om.get(x[id]||x.code)||{},cv=x[k]||{},ov=o[k]||{},rem=Math.max(N(cv.remaining)||(N(cv.target)-N(cv.actual)),0),per=N(cv.perDay)||(dl()>0?rem/dl():rem),r=cmpPair(cv,ov);return{...x,current:r.a,previous:r.b,remaining:rem,perDay:per,diff:r.d,indexNow:r.ix,indexOld:r.oi}})}function drow(r,i,s=null){const cls=r.diff>=0?'up':'dn',tag=s?'button':'div',attr=s?` data-mode='${E(s.mode||'compare')}' data-cat='${E(s.cat||'')}' data-ads='${E(s.ads||'')}' data-cmp='${E(state.cmp||'prev')}'`:'';const txt=state.cmp==='pace'?`เพิ่ม ${M(r.current)} / Pace ${M(r.previous)}`:`ล่าสุด ${M(r.current)} / ก่อนหน้า ${M(r.previous)}`;return`<${tag} class='row'${attr}><div class='no'>${i+1}</div><div class='rowMain'><div class='rowHead'><b>${E(r.ps||r.ads||r.code)} · ${E(r.name||'')}</b><em class='paceMini'>เหลือ ${M(r.remaining)} / วันละ ${M(r.perDay)}</em></div><span class='rowSub'>${txt} / Index ${P(r.indexNow)}</span></div><div class='right ${cls}'>${r.diff>=0?'+':''}${M(r.diff)}</div></${tag}>`}
function chipCat(cat,ad){return`<div class='chips'>${K().map(k=>btn(C[k],{mode:'compare',cat:k,ads:ad||'',cmp:state.cmp||'prev'},'chip')).join('')}</div>`}function chipAds(list,cat,ad){return`<div class='chips'>${(list||[]).map(a=>btn(a,{mode:'compare',cat,ads:a,cmp:state.cmp||'prev'},'chip')).join('')}</div>`}function causePanel(rows){const low=[...rows].sort((a,b)=>a.diff-b.diff).slice(0,5);return`<section class='panel'><h3>Cause Dashboard</h3><div class='muted'>เรียงจากจุดที่ลดลงหรือทำต่ำกว่าก่อน เพื่อใช้ไล่สาเหตุ</div><div class='rank'>${low.map((r,i)=>drow(r,i)).join('')||`<div class='empty'>ยังไม่มีข้อมูลสาเหตุ</div>`}</div></section>`}function problemPanel(rows){const prob=[...rows].sort((a,b)=>b.remaining-a.remaining).slice(0,5);return`<section class='panel'><h3>Problem Dashboard</h3><div class='muted'>PS/ADS ที่ยังเหลือเป้าสูงสุด ต้องเร่งก่อน</div><div class='rank'>${prob.map((r,i)=>drow(r,i)).join('')||`<div class='empty'>ยังไม่มีข้อมูลปัญหา</div>`}</div></section>`}
async function screenCompare(seq){let p;try{p=await oldPack(state.cmp||'prev')}catch(e){if(seq!==renderSeq||state.mode!=='compare')return;app.innerHTML=nav()+`<section class='panel'><div class='empty'>${E(e.message)}</div></section>`;return}if(seq!==renderSeq||state.mode!=='compare')return;const prev=oldLabel(p.pick),cat=state.cat in C?state.cat:'';if(!cat){app.innerHTML=nav()+statusPanel()+hero('Smart Compare วันต่อวัน','ล่าสุด '+(data.meta?.reportKey||'')+' เทียบกับ '+prev,data.ds)+`<section class='panel'><h3>DS Compare</h3>${cmpSlider()}<div class='catgrid'>${K().map((k,i)=>diffBtn(data.ds,p.old.ds||{},k,i)).join('')}</div></section>`+trendPanel();return}const adsRows=deltas(data.ads,p.old.ads,cat,'ads').sort((a,b)=>b.diff-a.diff),adsList=adsRows.map(x=>x.ads||x.code).filter(Boolean),sel=state.ads&&adsList.includes(state.ads)?state.ads:'',dsNow=data.ds?.[cat]||{},dsOld=p.old.ds?.[cat]||{},dsDiff=N(dsNow.actual)-N(dsOld.actual),x=pc(dsNow);if(sel){const curPs=(data.ps||[]).filter(x=>x.ads===sel),oldPs=(p.old.ps||[]).filter(x=>x.ads===sel),rows=deltas(curPs,oldPs,cat,'ps'),up=[...rows].sort((a,b)=>b.diff-a.diff),down=[...rows].sort((a,b)=>a.diff-b.diff),curAds=(data.ads||[]).find(x=>(x.ads||x.code)===sel)||sum(curPs,sel),oldAds=(p.old.ads||[]).find(x=>(x.ads||x.code)===sel)||sum(oldPs,sel),aNow=curAds[cat]||{},aOld=oldAds[cat]||{},aDiff=N(aNow.actual)-N(aOld.actual),ap=pc(aNow);if(seq!==renderSeq||state.mode!=='compare')return;app.innerHTML=nav()+`<section class='panel fade'><button class='chip' data-mode='compare' data-cat='${E(cat)}' data-cmp='${E(state.cmp||'prev')}'>← กลับรายละเอียด ${E(C[cat])}</button><div class='title'>${E(sel)} · ${E(C[cat])}</div><div class='muted'>ล่าสุด ${E(data.meta?.reportKey||'')} เทียบกับ ${E(prev)}</div>${cmpSlider()}${chipCat(cat,sel)}${chipAds(adsList,cat,sel)}<div class='kpis'><div class='kpi'><span>ADS ล่าสุด</span><b>${M(aNow.actual)}</b><small>${E(sel)}</small></div><div class='kpi'><span>ADS ก่อนหน้า</span><b>${M(aOld.actual)}</b><small>${E(sel)}</small></div><div class='kpi'><span>ADS เพิ่ม/ลด</span><b class='${aDiff>=0?'up':'dn'}'>${aDiff>=0?'+':''}${M(aDiff)}</b><small>รวมทีม</small></div><div class='kpi'><span>เหลือเป้า</span><b>${M(ap.r)}</b><small>${E(C[cat])}</small></div><div class='kpi'><span>ต้องทำ/วัน</span><b>${M(ap.p)}</b><small>เหลือ ${M(ap.d)} วัน</small></div><div class='kpi'><span>Index ล่าสุด</span><b>${P(aNow.index)}</b><small>ADS</small></div><div class='kpi'><span>Index ก่อนหน้า</span><b>${P(aOld.index)}</b><small>ADS</small></div><div class='kpi'><span>จำนวน PS</span><b>${rows.length}</b><small>ในทีม</small></div></div></section><div class='two fade'><section class='panel'><h3>PS ดีขึ้นใน ${E(sel)}</h3><div class='rank'>${up.map((r,i)=>drow(r,i)).join('')}</div></section><section class='panel'><h3>PS ต่ำลงใน ${E(sel)}</h3><div class='rank'>${down.map((r,i)=>drow(r,i)).join('')}</div></section></div>`;return}const allPs=deltas(data.ps,p.old.ps,cat,'ps'),allUp=[...allPs].sort((a,b)=>b.diff-a.diff).slice(0,12),allDown=[...allPs].sort((a,b)=>a.diff-b.diff).slice(0,12);if(seq!==renderSeq||state.mode!=='compare')return;app.innerHTML=nav()+`<section class='panel fade'><button class='chip' data-mode='compare' data-cmp='${E(state.cmp||'prev')}'>← กลับ DS Compare</button><div class='title'>รายละเอียด: ${E(C[cat])}</div><div class='muted'>ล่าสุด ${E(data.meta?.reportKey||'')} เทียบกับ ${E(prev)}</div>${cmpSlider()}${chipCat(cat,'')}<div class='kpis'><div class='kpi'><span>DS ล่าสุด</span><b>${M(dsNow.actual)}</b><small>${E(C[cat])}</small></div><div class='kpi'><span>DS ก่อนหน้า</span><b>${M(dsOld.actual)}</b><small>${E(C[cat])}</small></div><div class='kpi'><span>DS เพิ่ม/ลด</span><b class='${dsDiff>=0?'up':'dn'}'>${dsDiff>=0?'+':''}${M(dsDiff)}</b><small>รวมทั้งหมด</small></div><div class='kpi'><span>เหลือเป้า</span><b>${M(x.r)}</b><small>${E(C[cat])}</small></div><div class='kpi'><span>ต้องทำ/วัน</span><b>${M(x.p)}</b><small>เหลือ ${M(x.d)} วัน</small></div><div class='kpi'><span>Index ล่าสุด</span><b>${P(dsNow.index)}</b><small>ตามชีท</small></div><div class='kpi'><span>Index ก่อนหน้า</span><b>${P(dsOld.index)}</b><small>ตามชีท</small></div><div class='kpi'><span>Index ต่าง</span><b>${(N(dsNow.index)-N(dsOld.index))>=0?'+':''}${P(N(dsNow.index)-N(dsOld.index))}</b><small>จุด</small></div></div></section><section class='panel fade'><h3>ADS เปลี่ยนแปลง</h3><div class='rank'>${adsRows.map((r,i)=>drow(r,i,{mode:'compare',cat,ads:r.ads||r.code})).join('')}</div></section><div class='two fade'><section class='panel'><h3>PS ดีขึ้นมากสุด</h3><div class='rank'>${allUp.map((r,i)=>drow(r,i)).join('')}</div></section><section class='panel'><h3>PS ต่ำลงมากสุด</h3><div class='rank'>${allDown.map((r,i)=>drow(r,i)).join('')}</div></section></div><div class='two fade'>${causePanel(allPs)}${problemPanel(allPs)}</div>`}
function screenMs(){return nav()+`<section class='panel fade'><div class='title'>MS แยกโหมด</div><div class='empty'>โหมดนี้ถูกแยกจาก DS/ADS/PS แล้ว และยังไม่มี dataset MS ใน current.min.json จึงไม่แสดงตารางปลอม ถ้ามีไฟล์ MS เพิ่มเข้ามา ระบบควรต่อข้อมูลชุดใหม่โดยไม่ปนกับหน้า Pro หรือ DS.</div></section>`}
function render(){const seq=++renderSeq;if(!data){app.innerHTML=`<section class='panel'><div class='empty'>กำลังโหลดข้อมูล...</div></section>`;return}if(state.mode==='ads')app.innerHTML=screenAds();else if(state.mode==='ps')app.innerHTML=screenPs();else if(state.mode==='person')app.innerHTML=screenPerson();else if(state.mode==='compare')screenCompare(seq);else if(state.mode==='ms')app.innerHTML=screenMs();else app.innerHTML=screenDs()}
load().catch(e=>{app.innerHTML=nav()+`<section class='panel'><div class='title'>ยังไม่พบข้อมูลแบบเร็ว</div><div class='empty'>${E(e.message)}<br><br>ให้ไป Admin → เลือกไฟล์ Tracking → อัปโหลด Performance JSON + ตั้งล่าสุด</div></section>`})
})();